import type { ReactElement } from 'react';
import type { FilterFieldError } from './filter-field-error.js';
import type { FilterFieldDurationNode, FilterFieldLeafNode, FilterFieldStatementNode } from './tree-nodes.js';
/**
 * Comparison operator values for restricting the valid comparison operators in the FilterField ValidatorMap.
 * @public
 */
export type FilterFieldComparisonOperators = 'equals' | 'not-equals' | 'less-than' | 'less-or-equal' | 'greater-than' | 'greater-or-equal' | 'exists' | 'not-exists' | 'in' | 'not in' | 'starts-with' | 'ends-with' | 'contains' | 'not-starts-with' | 'not-ends-with' | 'not-contains' | 'matches-phrase' | 'not-matches-phrase' | 'search';
/**
 * Names of types for values supported by the FilterField.
 * @public
 */
export type FilterFieldPrimitive = 'Number' | 'String' | 'Boolean' | 'Duration' | 'JSONPath' | 'IPAddress' | 'UID' | 'Timestamp' | 'SmartscapeId' | 'Any';
/**
 * Map of custom types and their validation functions.
 * @public
 */
export type FilterFieldCustomTypes = Record<string, ((value: string) => boolean) | {
    /** Validation function to check whether a given value is of the given type. */
    valuePredicate: (value: string) => boolean;
    /** Icon to render for suggestions of this type. */
    icon?: ReactElement;
    /** Label for the type name that is used in error messages. If no label is provided, the type name will be used. */
    label?: string;
}>;
/**
 * FilterField Duration type.
 * @deprecated Passing a duration as separate value and unit is deprecated. Pass a string value instead.
 * @public
 */
export type FilterFieldDuration = Required<Pick<FilterFieldDurationNode, 'value' | 'unit'>>;
/**
 * FilterField type definition for validator map.
 * Can be a single type or an array of types used for a key
 * directly or provided in the `valuePredicate` prop.
 * E.g.
 * ```
 * {
 *  keyPredicates: {
 *    a: { type: 'String' },
 *    b: {
 *      type: ['String', 'Number'],
 *    },
 *    c: {
 *      valuePredicate: {
 *        type: ['String', 'Number'],
 *      },
 *    },
 *  }
 * }
 * ```
 * @deprecated Use `valueType` on `FilterFieldKeySuggestionConfig` to restrict value types.
 * @public
 */
export type FilterFieldValidatorMapTypePredicate = Record<'type', FilterFieldPrimitive | string | (FilterFieldPrimitive | string)[]>;
/**
 * Value predicate with optional metadata for displaying in suggestions.
 * Allows specifying displayValue and details for value suggestions.
 * @public
 */
export type FilterFieldRichValuePredicate = {
    /**
     * The actual value to apply when the suggestion is selected.
     */
    value: string | number | boolean;
    /**
     * The display value to show for the value suggestion.
     * If not set, the value is used.
     */
    displayValue?: string;
    /**
     * Additional information to render for the value suggestion.
     */
    details?: string;
};
/**
 * Primitive value item for restricting valid values in the FilterField validatorMap.
 * Used as individual suggestions within a `FilterFieldValueSuggestionGroupConfig`.
 * @public
 */
export type FilterFieldValuePredicateItem = FilterFieldValidatorMapTypePredicate
/** String literal allowed for the value of the given key. */
 | string
/** Number value allowed for the value of the given key. */
 | number
/** Boolean value allowed for the value of the given key. */
 | boolean | FilterFieldDuration
/** Value with optional displayValue and details. */
 | FilterFieldRichValuePredicate;
/**
 * Configuration for a group of value suggestions in the FilterField validatorMap.
 * @public
 */
export type FilterFieldValueSuggestionGroupConfig = {
    /**
     * Unique identifier for the group. Used as the key in groupedSuggestions.
     * Falls back to label, then aria-label, then an auto-generated id.
     */
    id?: string;
    /** Visible label for the suggestion group. */
    label?: string;
    /** Accessible label for screen readers. */
    'aria-label'?: string;
    /** Suggestions within this group. */
    suggestions: FilterFieldValuePredicateItem[];
};
/**
 * Value predicate for restricting the valid values in the FilterField validatorMap.
 * @public
 */
export type FilterFieldValuePredicate = FilterFieldValuePredicateItem
/** Grouped value suggestions for the value of the given key. */
 | FilterFieldValueSuggestionGroupConfig
/** Value literals or grouped value suggestions allowed for the value of the given key. */
 | Array<FilterFieldValuePredicateItem | FilterFieldValueSuggestionGroupConfig>;
/**
 * Function executed for validating the value of a filter field statement.
 * - Returning true, the value is considered valid.
 * - Returning false, the value is considered erroneous and an error mark will be
 *   added to the filter field.
 * - Returning a string, the value is considered erroneous, an error mark and a
 *   tooltip with the given message will be added to the filter field.
 * @public
 */
export type FilterFieldValuePredicateFn = (state: {
    /** The statement currently being validated. */
    currentStatement: FilterFieldStatementNode;
    /** The current value of the FilterField. */
    filterFieldValue: string;
}) => boolean | string;
/**
 * ValidatorMap to restrict allowed keys, comparison operators and their values in the FilterField.
 *
 * The object notation of the `keyPredicates` is deprecated in favor of the array notation using `FilterFieldKeySuggestionConfig` and `FilterFieldKeySuggestionGroupConfig`,
 * which also supports grouping suggestions.
 *
 * Providing a `FilterFieldValidatorMapTypePredicate` directly in the `keyPredicates` object or as an item in the `valuePredicate` array is deprecated.
 * Use `valueType` on `FilterFieldKeySuggestionConfig` instead to restrict value types.
 * @public
 */
export type FilterFieldValidatorMap = {
    /** Object used for validating keys in the filter field. */
    keyPredicates?: // DEPRECATION: [APPDEV-16872] BREAKING-CHANGE
    {
        [key: string]: {
            comparisonOperators?: Array<FilterFieldComparisonOperators>;
            valuePredicate?: FilterFieldValuePredicate | FilterFieldValuePredicateFn;
            fallbackKey?: boolean | Array<Exclude<FilterFieldComparisonOperators, 'exists' | 'not-exists'>>;
            suggestStatementOnValueMatch?: boolean | FilterFieldValueMatchFn;
            displayValue?: string;
            details?: string;
        } | FilterFieldValidatorMapTypePredicate;
    }
    /**
     * Array of key names, key configs, or grouped key configs.
     * Supports grouping key suggestions under named section headers.
     * Ungrouped string entries and `FilterFieldKeySuggestionConfig` items fall
     * into the default key group. Mixed with the deprecated object format,
     * the array format takes precedence.
     */
     | Array<string | FilterFieldKeySuggestionConfig | FilterFieldKeySuggestionGroupConfig>;
    /**
     * Whether the provided key predicates are exhaustive.
     * If set to true, all keys not included in the object will be considered as errors.
     * If false, users can still use any other keys / values in the filter field.
     * @defaultValue true
     */
    exhaustive?: boolean;
    /**
     * Limits the allowed comparison operators, if unset, the following comparison operators are allowed:
     * <code>
     * 'equals', 'not-equals', 'less-than', 'less-or-equal', 'greater-than', 'greater-or-equal',
     * 'exists', 'not-exists', 'in', 'not in', 'starts-with', 'ends-with', 'contains'
     * </code>
     **/
    comparisonOperators?: Array<FilterFieldComparisonOperators>;
    /**
     * Whether default sorting of suggestions should be enabled/disabled.   * If set to false, suggestions follow the order defined in the validatorMap.
     * @defaultValue true
     */
    sortSuggestions?: boolean;
};
/**
 * Configuration for a single key suggestion in the FilterField validatorMap.
 * @public
 */
export type FilterFieldKeySuggestionConfig = {
    /** The key value used in the filter statement. */
    key: string;
    /** The type of values allowed for this key. Accepts built-in primitives or custom type names registered via `customTypes`. */
    valueType?: FilterFieldPrimitive | (string & {}) | (FilterFieldPrimitive | (string & {}))[];
    /** Allowed comparison operators for this key. */
    comparisonOperators?: Array<FilterFieldComparisonOperators>;
    /** Value predicate for restricting valid values. Use `valueType` to restrict value types instead of `FilterFieldValidatorMapTypePredicate`. */
    valuePredicate?: FilterFieldValuePredicate | FilterFieldValuePredicateFn;
    /** Whether this key acts as a fallback key. */
    fallbackKey?: boolean | Array<Exclude<FilterFieldComparisonOperators, 'exists' | 'not-exists'>>;
    /** Whether to suggest this key as a statement on value match. */
    suggestStatementOnValueMatch?: boolean | FilterFieldValueMatchFn;
    /**
     * The display value to show for the value suggestion.
     * If not set, the key is used.
     */
    displayValue?: string;
    /** Additional information to render for the key suggestion. */
    details?: string;
};
/**
 * Configuration for a group of key suggestions in the FilterField validatorMap.
 * @public
 */
export type FilterFieldKeySuggestionGroupConfig = {
    /**
     * Unique identifier for the group. Used as the key in groupedSuggestions.
     * Falls back to label, then aria-label, then an auto-generated id.
     */
    id?: string;
    /** Visible label for the suggestion group. */
    label?: string;
    /** Accessible label for screen readers. */
    'aria-label'?: string;
    /** Suggestions within this group. */
    suggestions: Array<string | FilterFieldKeySuggestionConfig>;
};
/**
 * Function executed for checking whether the key should be suggested as a statement suggestion with the current token as a value.
 * @public
 */
export type FilterFieldValueMatchFn = (currentToken: FilterFieldLeafNode) => boolean;
/** @internal */
export type PositionOperators = {
    type?: 'starts-with' | 'ends-with' | 'contains';
    ranges: Array<FilterFieldError['range']>;
};
